mapper.delete:
DELETE FROM core_visualization_jump_target_snapshot
WHERE link_jump_info_id IN (
    SELECT lji.id
    FROM core_visualization_jump_action_snapshot lji
    JOIN core_visualization_jump_snapshot lj ON lji.link_jump_id = lj.id
    WHERE lj.source_dv_id = #{dvId}
      AND lj.source_view_id = #{viewId}
);

DELETE FROM core_visualization_jump_action_snapshot
WHERE link_jump_id IN (
    SELECT lj.id
    FROM core_visualization_jump_snapshot lj
    WHERE lj.source_dv_id = #{dvId}
      AND lj.source_view_id = #{viewId}
);

DELETE FROM core_visualization_jump_snapshot
WHERE source_dv_id = #{dvId}
  AND source_view_id = #{viewId}

DELETE FROM core_visualization_jump_action
WHERE link_jump_id IN (
    SELECT lj.id
    FROM core_visualization_jump lj
    WHERE lj.source_dv_id = #{dvId}
)

DELETE FROM core_visualization_jump_action_snapshot
WHERE link_jump_id IN (
    SELECT lj.id
    FROM core_visualization_jump_snapshot lj
    WHERE lj.source_dv_id = #{dvId}
)

mapper.select:
SELECT DISTINCT
TO_CHAR(lj.source_view_id) || '#' || TO_CHAR(jtvi.source_field_active_id) || '#' || TO_CHAR(lji.source_field_id) AS sourceInfo, TO_CHAR(jtvi.target_view_id) || '#' || TO_CHAR(jtvi.target_field_id) AS targetInfo
concat( lj.source_view_id, '#', jtvi.source_field_active_id, '#', lji.source_field_id ) AS sourceInfo, concat( jtvi.target_view_id, '#', jtvi.target_field_id ) AS targetInfo
FROM core_visualization_jump_target jtvi LEFT JOIN core_visualization_jump_action lji ON jtvi.link_jump_info_id = lji.id LEFT JOIN core_visualization_jump lj ON lji.link_jump_id = lj.id WHERE lji.checked = 1 and lj.source_dv_id = #{request.sourceDvId} AND lj.source_view_id = #{request.sourceViewId} AND lji.target_dv_id = #{request.targetDvId}
AND lji.source_field_id = #{request.sourceFieldId}

SELECT DISTINCT
TO_CHAR(lj.source_view_id) || '#' || TO_CHAR(jtvi.source_field_active_id) || '#' || TO_CHAR(lji.source_field_id) AS sourceInfo, TO_CHAR(jtvi.target_view_id) || '#' || TO_CHAR(jtvi.target_field_id) AS targetInfo
concat( lj.source_view_id, '#', jtvi.source_field_active_id, '#', lji.source_field_id ) AS sourceInfo, concat( jtvi.target_view_id, '#', jtvi.target_field_id ) AS targetInfo
FROM core_visualization_jump_target_snapshot jtvi LEFT JOIN core_visualization_jump_action_snapshot lji ON jtvi.link_jump_info_id = lji.id LEFT JOIN core_visualization_jump_snapshot lj ON lji.link_jump_id = lj.id WHERE lji.checked = 1 and lj.source_dv_id = #{request.sourceDvId} AND lj.source_view_id = #{request.sourceViewId} AND lji.target_dv_id = #{request.targetDvId}
AND lji.source_field_id = #{request.sourceFieldId}
